"use client";
import { useEffect,useState } from "react";
import { AdminVendor,getAdminVendors,setVendorApproval } from "../../../lib/admin-api";
const colors:Record<string,string>={pending:"bg-amber-50 text-amber-800",approved:"bg-emerald-50 text-emerald-800",rejected:"bg-red-50 text-red-800"};
export default function AdminVendors(){const [vendors,setVendors]=useState<AdminVendor[]>([]);const [error,setError]=useState("");const [notice,setNotice]=useState("");const [loading,setLoading]=useState(true);const [working,setWorking]=useState<number|null>(null);const load=()=>{setLoading(true);getAdminVendors().then(d=>{setVendors(d.vendors);setError("");}).catch(e=>setError(e.message||"Unable to load vendors.")).finally(()=>setLoading(false));};useEffect(load,[]);async function decide(v:AdminVendor,action:"approve"|"reject"){if(!window.confirm(`${action==="approve"?"Approve":"Reject"} ${v.businessName}?`))return;setWorking(v.id);try{const d=await setVendorApproval(v.id,action);setVendors(x=>x.map(i=>i.id===v.id?{...i,approvalStatus:d.vendor.approvalStatus}:i));setNotice(`${v.businessName} is now ${d.vendor.approvalStatus}.`);}catch(e:any){setError(e.message||"Unable to update vendor.");}finally{setWorking(null);}}return <div><p className="text-sm font-bold uppercase tracking-[.16em] text-[#8B000F]">Administration</p><h1 className="mt-2 font-serif text-4xl font-bold text-[#5c1632]">Vendor applications</h1><p className="mt-2 text-slate-600">Approve only complete business profiles. Approved vendors become visible in the public catalog.</p>{notice&&<p role="status" className="mt-5 rounded-xl bg-emerald-50 p-4 text-emerald-800">{notice}</p>}{error&&<div role="alert" className="mt-5 rounded-xl bg-red-50 p-4 text-red-800">{error}<button onClick={load} className="ml-3 font-semibold underline">Retry</button></div>}<div className="mt-7 grid gap-4">{loading?Array.from({length:3}).map((_,i)=><div key={i} className="h-36 animate-pulse rounded-2xl bg-slate-100"/>):vendors.map(v=><article key={v.id} className="rounded-2xl border border-[#f0ded8] bg-white p-5 shadow-sm"><div className="flex flex-col justify-between gap-4 sm:flex-row"><div><h2 className="text-lg font-bold text-[#6b1839]">{v.businessName}</h2><p className="mt-1 text-slate-700">{v.categoryName||"Uncategorized"} · {v.city}</p><p className="mt-2 text-sm text-slate-600">Owner: {v.ownerName||v.email} · Registered {new Date(v.createdAt).toLocaleDateString("en-IN")}</p></div><div className="flex flex-wrap items-start gap-2"><span className={`rounded-full px-3 py-1 text-sm font-semibold ${colors[v.approvalStatus]||"bg-slate-100"}`}>{v.approvalStatus}</span>{v.approvalStatus==="pending"&&<><button disabled={working===v.id} onClick={()=>decide(v,"approve")} className="rounded-lg bg-emerald-700 px-3 py-2 text-sm font-semibold text-white disabled:opacity-60">Approve</button><button disabled={working===v.id} onClick={()=>decide(v,"reject")} className="rounded-lg bg-red-700 px-3 py-2 text-sm font-semibold text-white disabled:opacity-60">Reject</button></>}</div></div></article>)}{!loading&&!vendors.length&&<div className="rounded-2xl border border-dashed border-[#d9bcb1] bg-white p-10 text-center">No vendor applications yet.</div>}</div></div>}
